//
//  TopicTalkViewController.m
//  AiChat
//
//  Created by 芯竹 on 2024/11/7.
//

#import "TopicTalkViewController.h"
#import "MessageSendView.h"
#import "MessageModel.h"
#import "ChatMessageCell.h"

@interface TopicTalkViewController () <UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate, NSURLSessionDataDelegate>

@property(strong, nonatomic) MessageSendView *messageView;
@property(strong, nonatomic) UITableView *chatTableView;
@property(strong, nonatomic) NSMutableArray<MessageModel *> *messages;
@property (nonatomic, assign) BOOL isDeleting;
// 以下属性用于消息拼接实现流式显示效果
@property(strong, nonatomic) NSMutableString *accumulatedResponse;
@property(strong, nonatomic) NSMutableString *buffer;
@property(strong, nonatomic) NSString *nowString;
@property(strong, nonatomic) NSString *preString;
@property (nonatomic, strong) NSURLSessionDataTask *dataTask;
@property (nonatomic, strong) NSArray *context;

@end

@implementation TopicTalkViewController
#pragma mark - Initialization


- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];

    }
    return self;
}

- (instancetype)initWithAccount:(AccountModel *)account Data:(NSString *)options{
    self = [super init];
    if (self) {
        // 在初始化时进行赋值
        self.name = account.aiName;
        self.aiID = account.ID;
        self.headerView.titleLabel.text = account.aiName;
        self.headerView.editButton.hidden = YES;
        self.iconimage = [UIImage imageNamed:@"My_image"];
        self.options = options;
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];
    }
    return self;
}

- (void)addObservers {

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];
    // 添加通知观察者
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onSendMessageButtonTapped:) name:@"发送了一条消息" object:nil];
}

#pragma mark - loadView & viewDidLoad & viewDidAppear & dealloc

- (void)loadView { // 创建并设置视图控制器的 view 属性
    [super loadView];
    [self setUpUI];
}

- (void)viewDidLoad { // 在视图控制器的 view 属性已经被加载到内存后调用。此时视图层次结构已经创建完成，通常用于视图的额外配置和初始化。
    [super viewDidLoad];
    self.accumulatedResponse = [[NSMutableString alloc] init];
    self.buffer = [[NSMutableString alloc] init];
    self.isDeleting=NO;
    [self setupMessages]; // 初始化消息数组
    [self setupDelegates]; // 设置代理
    [self scrollToBottom]; // 滚动到最下方最新消息
}

- (void)viewDidAppear:(BOOL)animated { //会在视图控制器的视图已经完全显示并且用户可以看到时被调用
    [super viewDidAppear:animated];
    [_headerView showAppearAnimation];
    [self.chatTableView reloadData]; // 刷新表格视图以显示消息
}

- (void)viewDidDisappear:(BOOL)animated {
    [super viewDidDisappear:animated];
    // 删除操作时出现一些bug，目前只能通过这种方法修改
    // 检测最后一条消息是否已经显示出来了，如果已经显示出来了就保留，如果还是"思考中"则删除最后一条消息
    if((![self.messages.lastObject.text isEqual:@"思考中..."])&&self.messages.count>1&&(!self.messages.lastObject.done)&&(!self.isDeleting)){
        self.messages.lastObject.context = self.messages[self.messages.count-3].context;
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count-2].done=YES;
        self.messages[self.messages.count-3].context=@"";
        [MessageModel saveMessagesForAccount:self.aiID]; // 保存消息
        self.messageView.inputMessageField.enabled = YES;
        self.messageView.sendButton.enabled = YES; // 按钮恢复可点击
        self.messageView.sendButton.alpha = 1.0; // 恢复透明度
    }
    // 删除时也需要检测是否有任务存在且未完成，有则取消任务
    if (self.dataTask) {
        [self.dataTask cancel];
        self.dataTask = nil;  // 释放任务
    }
}

- (void)dealloc { //当一个视图控制器的生命周期结束且没有其他地方再引用它时，dealloc 会被调用。
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark - UI Setup

- (void)setUpUI {
    [self.view addSubview…11888 chars truncated…onseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
    if (jsonError) {
        NSLog(@"Failed to parse JSON from server response: %@", jsonError);
        //不确定是否是因为消息被切断而导致的json解析出错，所以需要进行拼接
        [self.buffer appendString:jsonString];
        // 检测最后一个字符，如果是'}'，则代表是消息被切断导致的，json解析最后一条消息
        if([self.buffer characterAtIndex:self.buffer.length - 1]==closingBrace){
            NSLog(@"已拼接最后一条消息");
            // 注意：复用jsonError时要赋空
            jsonError = nil;
            jsonData = [self.buffer dataUsingEncoding:NSUTF8StringEncoding];
            responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
            if(jsonError){
                NSLog(@"Failed to parse JSON from server response: %@", jsonError);
                NSLog(@"接收到的服务器消息: %@", self.buffer);
                return;
            }
            BOOL done = [responseDict[@"done"] boolValue];
            if(done){
                [self processDoneMessage:responseDict];
            }
        }
        return; // 跳过解析失败的消息
    }
    _preString = _nowString;
    _nowString = responseDict[@"response"];
    BOOL done = [responseDict[@"done"] boolValue];
    if (done) {
        [self processDoneMessage:responseDict];
    }
    if (_preString) {
        _preString = [_preString stringByReplacingOccurrencesOfString:@"*" withString:@""];
        _preString = [_preString stringByReplacingOccurrencesOfString:@"\n\n+" withString:@"\n" options:NSRegularExpressionSearch range:NSMakeRange(0, _preString.length)];
        [self.accumulatedResponse appendString:_preString];
        // 更新最后一条消息
        MessageModel *lastMessage = [self.messages lastObject];
        lastMessage.text = self.accumulatedResponse;
        lastMessage.cellHeight = [self getStringWidthToCellHeight:self.accumulatedResponse];
        dispatch_async(dispatch_get_main_queue(), ^{
            [self.chatTableView reloadData];
            [self scrollToBottom];
        });
    }
}
- (void)processDoneMessage:(NSDictionary *)Dict{
    dispatch_async(dispatch_get_main_queue(), ^{
        // 提取 context
        NSArray *lastContext = self.context;
        NSArray *ReContext = Dict[@"context"];
        // 确保不超出 bounds
        NSRange range;
        NSArray *contextArray;
        // 确保不超出 bounds
        if (ReContext.count == 1||lastContext.count < ReContext.count) {  //服务器哪里有一个特殊消息，里面的context=[1];
            // 当 ReContext.count 为 1 时，直接将 contextArray 设为 lastContext
            contextArray = lastContext;
        } else {
            range = NSMakeRange(lastContext.count, ReContext.count - lastContext.count);
            contextArray = [ReContext subarrayWithRange:range];
        }
        NSError *error;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:contextArray options:0 error:&error];
        if (!error) {
            self.messages.lastObject.context = [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding];
            NSLog(@"Converted string: %@", self.messages.lastObject.context);
        } else {
            NSLog(@"Error converting array to JSON string: %@", error.localizedDescription);
        }
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count-2].done=YES;
        self.messages[self.messages.count-3].context=@"";
        [MessageModel saveMessagesForAccount:self.aiID]; // 保存消息
        self.messageView.inputMessageField.enabled = YES;
        self.messageView.sendButton.enabled = YES; // 按钮恢复可点击
        self.messageView.sendButton.alpha = 1.0; // 恢复透明度
        //[self.editView modifyTipWords:self.messages.lastObject.text]; // 修改最新聊天信息
        // 打印文件内容以验证
//        NSString *filePath = [MessageModel filePathForAccount:self.aiID];
//        NSData *data = [NSData dataWithContentsOfFile:filePath];
//        NSString *fileContent = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
//        NSLog(@"文件内容: %@", fileContent);
    });
    NSLog(@"响应结束");
    return;
}
#pragma mark - 懒加载
- (ShowHeaderView *)headerView {
    if (_headerView == nil) {
        _headerView = [[ShowHeaderView alloc] init];
    }
    return _headerView;
}
- (UITableView *)chatTableView {
    if (_chatTableView == nil) {
        _chatTableView = [[UITableView alloc] init];
        _chatTableView.backgroundColor=BACKGROUND_COLOR;
        _chatTableView.showsVerticalScrollIndicator = NO;
    }
    return _chatTableView;
}
- (MessageSendView *)messageView {
    if (_messageView == nil) {
        _messageView = [[MessageSendView alloc] init];
    }
    return _messageView;
}

@end

