- (instancetype)initWithText:(NSString *)text time:(NSDate *)time type:(AIChatListMessageType)type context:(NSString*)context Done:(BOOL)done {
    self = [super init];
    if (self) {
        _text = [text copy] ?: @"";
        _time = time ?: [NSDate date];
        _type = type;
        _context = [context copy] ?: @"";
        _done = done;
        _messagenum = 0;
    }
    return self;
}

