        if ([item.chatId isEqualToString:chatId]) { target = item; break; }
    }
    NSMutableArray<AIChatListMessageModel *> *msgs = [NSMutableArray array];
    if (target) {
        NSString *chatId = target.chatId ?: @"";
        if ([chatId isEqualToString:@"ai_chat_default_emotion"]) {
            NSArray *texts = @[ @"Halo, selamat datang. Anda dapat mengajukan pertanyaan emosional apa pun kepada saya, dan saya akan menjawabnya satu per satu untuk Anda.",
