            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([chatId isEqualToString:@"ai_chat_default_outdoor"]) {
            NSArray *texts = @[ @"Halo, apa olahraga favoritmu? Sepak bola; Bola basket; Lari; Renang; Berkuda?",
                                @"Saya biasanya lari 5 kilometer di pagi hari dan bermain bola di sore hari." ];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([chatId isEqualToString:@"ai_chat_default_music"]) {
            NSArray *texts = @[ @"Buka pemutar musik, dan berulang kali, hanya ada beberapa lagu yang tidak bisa Anda dengarkan dengan baik. Saya tidak tahu apa yang ingin Anda dengarkan, tetapi saya dapat memberi tahu Anda genre apa yang Anda sukai dan merekomendasikan beberapa lagu populer yang Anda sukai baru-baru ini.",
