                                 @"Perlu fokus pada studi/pekerjaan, rekomendasi musik murni." ];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        }
    }
    // 非示例项或未命中时，退化为一条通用问候语
    if (msgs.count == 0) {
        NSString *g1Text = @"Apakah kamu akan menonton film setelah kerja nanti malam?";
        AIChatListMessageModel *g1 = [[AIChatListMessageModel alloc] initWithText:g1Text time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
        [msgs addObject:g1];
    }
    return msgs;
