    // 预热网络，尽早触发系统网络权限弹窗或建立连接，避免首条真实消息被打断
    [[AIChatListServerManager sharedManager] warmUpNetwork:^(BOOL online) {
        if (!online) {
            NSString *msg = @"Jaringan tidak tersedia atau data seluler dibatasi. Anda bisa mengaktifkan izin jaringan aplikasi nanti di Pengaturan.";
            UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Jaringan tidak tersedia" message:msg preferredStyle:UIAlertControllerStyleAlert];
